타이머로 마지막 호출만 실행되게 합니다.

```js
function debounce(fn, delay = 300) {
  let timer;
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
}

// 사용
const onSearch = debounce((query) => {
  console.log("검색:", query);
}, 500);
```

